     5→export const useBookMarkMutation = (session, userId) => {
     6→    const queryClient = useQueryClient();
     7→    return useMutation({
     8→        mutationFn: (data) => addBookmark(session?.access_token, data),
     9→
    10→        onMutate: async(data) =>{
    11→            await queryClient.cancelQueries(['journals', userId])
    12→            const previousData = queryClient.getQueryData(['journals', userId]);
    13→
    14→            queryClient.setQueryData(['journals', userId], (old) => {
    15→                if(!old) return old;
    16→                
    17→                return{
    18→                    ...old,
    19→                    pages: old.pages.map((page) => ({
    20→                        ...page,
    21→                        data: page.data.map((journal) =>{
    22→                            if(journal.id !== data.journalId) return journal;
    23→
    24→                            const isBookmarked = journal.has_bookmarked;
    25→                            const count = journal.bookmark_count?.[0]?.count ?? 0;
    26→
    27→                            return{
    28→                                ...journal,
    29→                                has_bookmarked: !isBookmarked,
    30→                                bookmark_count: [{count: isBookmarked ? count - 1 : count + 1}]
    31→                            }
    32→                        })
    33→                    }))
    34→                }
    35→            })
    36→
    37→            return {previousData};
    38→        },
    39→        onError: (err,data, context) =>{
    40→            queryClient.setQueryData(['journals', userId], context.previousData)
    41→        },
    42→        onSettled: () =>{
    43→            queryClient.invalidateQueries(['journals', userId])
    44→        }
    45→    })
    46→}
    47→
    48→
